// // This module is a 16-bit down counter with enable and reset signals. The counter should decrement on every clock cycle when enabled and reset to zero when the reset signal is high.
module counter_16bit (
    input clk,
    input reset,
    input enable,
    output reg [15:0] count
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 16'b0;
        end else if (enable) begin
            count <= count + 1;
        end
    end
endmodule
